import React, { Component } from 'react';
import PropTypes from 'prop-types';
import {connect} from 'react-redux';
import {withStyles} from '@material-ui/core/styles';
import { MyPopupMenu } from '../../../../includes';
import { sessionStrings, sessionActions } from '../../../Sessions';
import { accountStrings } from '../../config';
import { accountActions } from '../../actions';


const style = theme => ({
    root: {
        display : "flex",
        flexDirection : "row",
        // margin : 10
    }
})
class _MainStageComponent extends Component {
    constructor(props) {
        super(props);
        this.initializeComponent()
    }
    initializeComponent(){
        const {
            [sessionStrings.sessions] : sessions,
            dispatch
        } = this.props;
        if(!sessions) 
            sessionActions.getSessions()(dispatch);
        }
    selectSession = selectedSession => {
        const {dispatch} = this.props;
        accountActions.setSelectedSession(selectedSession)(dispatch);
        sessionActions.getSessionTerms(selectedSession._id)(dispatch);
    }
    selectTerm = selectedTerm => {
        const {dispatch} = this.props;
        accountActions.setSelectedTerm(selectedTerm)(dispatch);
        accountActions.getStudentFeeTx(selectedTerm._id)(dispatch);
    }
    render() {
        const {
            classes, 
            [sessionStrings.sessions] : sessions,
            [accountStrings.selectedSession] : selectedSession,
            [sessionStrings.terms] : sessionTerms,
            [accountStrings.selectedTerm] : selectedTerm,
        } = this.props;
        console.log(this.props);
        return (
            <div className={classes.root}>
                <MyPopupMenu
                    buttonName="session"
                    buttonValue={(selectedSession && selectedSession.name) ||"Session"}
                    options={sessions}
                    optionNameProp="name"
                    optionValueProp="_id"
                    optionClickCallback={this.selectSession.bind(this)}/>
                <MyPopupMenu
                    buttonName="terms"
                    buttonValue={(selectedTerm && selectedTerm.name) ||"Terms"}
                    options={sessionTerms}
                    optionNameProp="name"
                    optionValueProp="_id"
                    optionClickCallback={this.selectTerm.bind(this)}/>
            </div>
        );
    }
}


_MainStageComponent.propTypes = {
    classes : PropTypes.object.isRequired
};

const mapStateToProps = ({sessionReducer, accountReducer}) => ({
    [sessionStrings.sessions] : sessionReducer[sessionStrings.sessions],
    [accountStrings.selectedSession] : accountReducer[accountStrings.selectedSession],
    [sessionStrings.terms] : sessionReducer[sessionStrings.terms],
    [accountStrings.selectedTerm] : accountReducer[accountStrings.selectedTerm],
})


export const MainStageComponent = connect(mapStateToProps)(withStyles(style)(_MainStageComponent));