import React, { Component } from 'react';
import PropTypes from 'prop-types';
import {connect} from 'react-redux';
import {withStyles} from '@material-ui/core/styles';
import { headerStrings, headerActions, breadCrumbActions, mainStageHeaderAction, mainStageHeaderStrings, MyTable } from '../../../../includes';
import { colors } from '../../../../../utils';
import { MainStageComponent } from './MainStageComponent';
import { accountStrings } from '../../config';
import { TableCell, Typography, Button } from '@material-ui/core';
import { Done as DoneIcon } from '@material-ui/icons';
import { appActions } from '../../../../../actions';
import { routeNamesSchool } from '../../../routeNames';


const style = theme => ({
    root: {
    },
    text : {
        color : "orange",
        textTransform : "lowercase",
        border : "solid 1px orange",
        borderRadius : 5,
        padding : 2
    }
})
class _StudentFeeList extends Component {
    constructor(props) {
        super(props);
        this.state = {
            studentFeeList : null
        }
        const {dispatch} = props;
        headerActions({
            [headerStrings.headerTitle] : "ACCOUNT - FEES",
        })(dispatch);
        breadCrumbActions.setBreadCrumb([
            {name : "Dashboard", path : routeNamesSchool.dashboard},
            {name : "Account", path : routeNamesSchool.accountStatistics},
            {name : "Fees", path : routeNamesSchool.studentFees}
        ])(dispatch);
        mainStageHeaderAction({
            [mainStageHeaderStrings.buttons] : [
                {value : "New term fee",onClick : ()=>this.props.superSetState({page:"newTerm"}), style : {backgroundColor : colors.secondary}}
            ],
            [mainStageHeaderStrings.searchActions] : ()=>{},
            [mainStageHeaderStrings.components] : [
                MainStageComponent
            ]
        })(dispatch);
    }
    cellMapFormat = approvePayment=> ({row, cellMap}) =>{
        switch(cellMap){
            case "action" : return <TableCell style={{padding: 5}}>
                {row.completed ? 
                    <DoneIcon size={30} style={{color : colors.secondary}}/> :
                    <Button 
                        onClick={approvePayment(row)} 
                        classes={{text:this.props.classes.text}}>
                            Approve
                    </Button>}
            </TableCell>;
            default : return <TableCell style={{padding: 5}}>
                    <Typography>{row[cellMap]}</Typography>
            </TableCell>
        }
    }
    approvePayment = studentTx => (e) => {
        e.stopPropagation();
        console.log(studentTx);
        const {dispatch} = this.props;
        appActions.showSnackDialog(
            "Are you sure you want to approve payment by "+studentTx.fullName+"?",
            <Button key="continue" onClick={()=>{
                appActions.closeSnackDialog()(dispatch);
            }}>Continue</Button>
        )(dispatch);
    }
    render() {
        const {
            classes,
            [accountStrings.studentFeeList] : studentFeeList
        } = this.props;
        return (
            <div className={classes.root}>
                <MyTable
                    header={["Student ID", "Full Name", "Tx Ref", "Actions"]}
                    dataMap={["studentId", "fullName", "ref", "action"]}
                    data={studentFeeList || []}
                    CellMap={this.cellMapFormat(this.approvePayment)}/>
            </div>
        );
    }
}


_StudentFeeList.propTypes = {
    classes : PropTypes.object.isRequired,
    superSetState : PropTypes.func,
};

const mapStateToProps = ({accountReducer}) => ({
    [accountStrings.studentFeeList] : accountReducer[accountStrings.studentFeeList]
})


export const StudentFeeList = connect(mapStateToProps)(withStyles(style)(_StudentFeeList));