import React, { Component } from 'react';
import PropTypes from 'prop-types';
import {connect} from 'react-redux';
import {withStyles} from '@material-ui/core/styles';
import { NewTermFee } from './NewTermFee';
import { StudentFeeList } from './StudentFeeList/StudentFeeList';
import { customSuperSetState } from "../../../../utils";
import { MyCustomTabs } from '../../../includes';

const style = theme => ({
    root: {
        marginTop : 20
    }
})
class _Fees extends Component {
    constructor(props) {
        super(props);
        this.state = {
            tabValue : null
        }
        
    }
    mySetState = customSuperSetState(this);
    render() {
        const {classes} = this.props;
        const {tabValue} = this.state;
        return (
            <div className={classes.root}>
                <MyCustomTabs
                    position="sticky"
                    tabs={{
                        requests : "Payment Request",
                        newTerm : "New Term",
                    }}
                    getInitialTabValue={tabValue => this.setState({tabValue})}/>
                {tabValue === "requests" && <StudentFeeList
                    superSetState={this.mySetState}/>}
                {tabValue === "newTerm" && <NewTermFee goBack={()=>this.setState({page: "home"})}/>}
            </div>
        );
    }
}


_Fees.propTypes = {
    classes : PropTypes.object.isRequired
};

const mapStateToProps = state => ({
    state
})


export const Fees = connect(mapStateToProps)(withStyles(style)(_Fees));
export {Fees as default};